def remove_orphaned_attendance(apps, schema_editor):
    """Remove attendance rows with invalid subject_id (orphaned by deleted subjects)."""
    Attendance = apps.get_model('main_app', 'Attendance')
    Subject = apps.get_model('main_app', 'Subject')
    valid_subject_ids = set(Subject.objects.values_list('id', flat=True))
    if not valid_subject_ids:
        return
    orphaned = Attendance.objects.exclude(subject_id__in=valid_subject_ids)
    count = orphaned.count()
    orphaned.delete()
    if count:
        print(f"Removed {count} orphaned attendance record(s) with invalid subject_id.")


